SELECT id, longitude, latitude, address, create_time, update_time, expire_time
FROM acd_location_address_cache
WHERE id = #{id}

SELECT id, longitude, latitude, address, create_time, update_time, expire_time
FROM acd_location_address_cache
WHERE longitude = #{longitude} AND latitude = #{latitude}

SELECT id, longitude, latitude, address, create_time, update_time, expire_time
FROM acd_location_address_cache
WHERE longitude = #{longitude} AND latitude = #{latitude}
  AND expire_time >= #{currentTime}
LIMIT 1

SELECT id, longitude, latitude, address, create_time, update_time, expire_time
FROM acd_location_address_cache
WHERE address = #{address}

SELECT id, longitude, latitude, address, create_time, update_time, expire_time
FROM acd_location_address_cache
WHERE address = #{address}
  AND expire_time >= #{currentTime}

